class Solution {
public:
    int repeatedStringMatch(string a, string b) {
        int n = a.size(), m = b.size();
        int count = m / n + 3;
        string repeat = "";
        for (int i = 0; i < count; i++) {
            repeat += a;
        }
        int index = repeat.find(b);
        if (index == string::npos) {
            return -1;
        }
        int left = index / n;
        int right = (index + m - 1) / n;
        return right - left + 1;
    }
};
